ax":12,"rir":2}],"descanso":150,"ss":null},{"nombre":"Jalón al pecho","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":150,"ss":null},{"nombre":"Press militar sentada con mancuernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":120,"ss":null},{"nombre":"Remo en máquina","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":120,"ss":null},{"nombre":"Elevaciones laterales","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":90,"ss":null},{"nombre":"Crunch abdominal","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":60,"ss":null}]},{"nombre":"CUÁDRICEPS & GLÚTEO","ejercicios":[{"nombre":"Sentadilla","series":[{"reps":6,"reps_max":8,"rir":2},{"reps":6,"reps_max":8,"rir":2},{"reps":6,"reps_max":8,"rir":2}],"descanso":180,"ss":null},{"nombre":"Prensa de piernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":150,"ss":null},{"nombre":"Subida al cajón (step-up)","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":120,"ss":null},{"nombre":"Extensiones de rodillas en máquina de placas","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":120,"ss":null},{"nombre":"Hiperextensión con foco en glúteo","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":90,"ss":null},{"nombre":"Gemelo en prensa","series":[{"reps":10,"reps_max":15,"rir":2},{"reps":10,"reps_max":15,"rir":2},{"reps":10,"reps_max":15,"rir":2},{"reps":10,"reps_max":15,"rir":2}],"descanso":90,"ss":null}]}]},{"nombre":"Definición Full Body 3 días — Superseries","dias":[{"nombre":"FULL BODY 1","ejercicios":[{"nombre":"Prensa de piernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Jalón al pecho","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Press banca con mancuernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Curl femoral sentado","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Elevaciones laterales","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":60,"ss":"C"},{"nombre":"Crunch abdominal","series":[{"reps":15,"reps_max":20,"rir":2},{"reps":15,"reps_max":20,"rir":2},{"reps":15,"reps_max":20,"rir":2}],"descanso":60,"ss":"C"}]},{"nombre":"FULL BODY 2","ejercicios":[{"nombre":"Sentadilla goblet","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Remo en máquina","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Press militar sentada con mancuernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Peso muerto rumano con mancuernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Curl en polea baja","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":60,"ss":"C"},{"nombre":"Extensiones de codo desde polea alta","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":60,"ss":"C"}]},{"nombre":"FULL BODY 3","ejercicios":[{"nombre":"Hip thrust en máquina","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Dominadas asistidas en máquina","series":[{"reps":8,"reps_max":10,"rir":2},{"reps":8,"reps_max":10,"rir":2},{"reps":8,"reps_max":10,"rir":2}],"descanso":90,"ss":"A"},{"nombre":"Zancadas con mancuernas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Press plano en máquina de placas","series":[{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2},{"reps":10,"reps_max":12,"rir":2}],"descanso":90,"ss":"B"},{"nombre":"Abducciones de cadera sentada en máquina","series":[{"reps":15,"reps_max":20,"rir":2},{"reps":15,"reps_max":20,"rir":2},{"reps":15,"reps_max":20,"rir":2}],"descanso":60,"ss":"C"},{"nombre":"Elevaciones de piernas tumbado","series":[{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2},{"reps":12,"reps_max":15,"rir":2}],"descanso":60,"ss":"C"}]}]}]'::jsonb;
  v_plantilla jsonb;
  v_dia jsonb;
  v_ej jsonb;
  v_rutina uuid;
  v_dia_id uuid;
  v_rutejercicio_id uuid;
  v_ejercicio_id uuid;
  v_orden_dia int;
  v_orden_ej int;
begin
  for v_plantilla in select * from jsonb_array_elements(v_datos)
  loop
    -- si ya existe una plantilla con ese nombre, no duplicar
    if exists (
      select 1 from public.rutinas
      where es_plantilla and nombre = v_plantilla->>'nombre'
    ) then
      raise notice 'Ya existe, se omite: %', v_plantilla->>'nombre';
      continue;
    end if;

    insert into public.rutinas (nombre, es_plantilla, activa, semana_actual)
    values (v_plantilla->>'nombre', true, true, 1)
    returning id into v_rutina;

    v_orden_dia := 0;
    for v_dia in select * from jsonb_array_elements(v_plantilla->'dias')
    loop
      insert into public.rutina_dias (rutina_id, orden, nombre, semana)
      values (v_rutina, v_orden_dia, v_dia->>'nombre', 1)
      returning id into v_dia_id;
      v_orden_dia := v_orden_dia + 1;

      v_orden_ej := 0;
      for v_ej in select * from jsonb_array_elements(v_dia->'ejercicios')
      loop
        select id into v_ejercicio_id from public.ejercicios
        where nombre = v_ej->>'nombre'
        limit 1;

        if v_ejercicio_id is null then
          raise exception 'Ejercicio no encontrado en la biblioteca: %', v_ej->>'nombre';
        end if;

        insert into public.rutina_ejercicios
          (dia_id, ejercicio_id, orden, descanso_seg, grupo_superserie)
        values
          (v_dia_id, v_ejercicio_id, v_orden_ej, (v_ej->>'descanso')::int, v_ej->>'ss')
        returning id into v_rutejercicio_id;
        v_orden_ej := v_orden_ej + 1;

        insert into public.series_prescritas
          (rutina_ejercicio_id, orden, tipo, reps, reps_max, rir)
        select
          v_rutejercicio_id, (ord - 1)::int, 'efectiva',
          (se->>'reps')::int, (se->>'reps_max')::int, (se->>'rir')::int
        from jsonb_array_elements(v_ej->'series') with ordinality as t(se, ord);
      end loop;
    end loop;

    raise notice 'Plantilla creada: %', v_plantilla->>'nombre';
  end loop;
end $$;
